import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { AlertCircle, CheckCircle, AlertTriangle, Zap } from 'lucide-react';

const Recommendations = () => {
  const [recommendations, setRecommendations] = useState([]);
  const [selectedType, setSelectedType] = useState('AIR_QUALITY');
  const [selectedPriority, setSelectedPriority] = useState('HIGH');
  const [loading, setLoading] = useState(false);

  const pollutionTypes = [
    { value: 'AIR_QUALITY', label: 'Air Quality' },
    { value: 'WATER_QUALITY', label: 'Water Quality' },
    { value: 'NOISE_LEVEL', label: 'Noise Level' },
    { value: 'SOIL_POLLUTION', label: 'Soil Pollution' },
    { value: 'GENERAL', label: 'General' }
  ];

  const priorities = [
    { value: 'CRITICAL', label: 'Critical', color: '#8b0000' },
    { value: 'HIGH', label: 'High', color: '#d32f2f' },
    { value: 'MEDIUM', label: 'Medium', color: '#ff9800' },
    { value: 'LOW', label: 'Low', color: '#4caf50' }
  ];

  useEffect(() => {
    fetchRecommendations();
  }, [selectedType, selectedPriority]);

  const fetchRecommendations = async () => {
    try {
      setLoading(true);
      const response = await axios.get(
        `http://localhost:8080/api/recommendations/type/${selectedType}/priority/${selectedPriority}`
      );
      setRecommendations(response.data || []);
    } catch (error) {
      console.error('Error fetching recommendations:', error);
      setRecommendations([]);
    } finally {
      setLoading(false);
    }
  };

  const getCategoryIcon = (category) => {
    const iconMap = {
      'INDIVIDUAL_ACTION': <AlertTriangle size={20} />,
      'COMMUNITY_ACTION': <Zap size={20} />,
      'POLICY_CHANGE': <AlertCircle size={20} />,
      'INFRASTRUCTURE': <CheckCircle size={20} />,
      'BEHAVIOR_CHANGE': <AlertTriangle size={20} />,
      'EMERGENCY_ACTION': <AlertCircle size={20} />
    };
    return iconMap[category] || <AlertCircle size={20} />;
  };

  const getPriorityColor = (priority) => {
    const colorMap = {
      'CRITICAL': '#8b0000',
      'HIGH': '#d32f2f',
      'MEDIUM': '#ff9800',
      'LOW': '#4caf50'
    };
    return colorMap[priority] || '#999';
  };

  return (
    <div style={{ padding: '20px', backgroundColor: '#f5f5f5', minHeight: '100vh' }}>
      <h1>Pollution Control Recommendations</h1>
      
      <div style={{
        display: 'flex',
        gap: '20px',
        marginBottom: '30px',
        flexWrap: 'wrap',
        backgroundColor: '#fff',
        padding: '20px',
        borderRadius: '8px',
        boxShadow: '0 2px 8px rgba(0,0,0,0.1)'
      }}>
        <div style={{ flex: 1, minWidth: '200px' }}>
          <label htmlFor="type-select">
            <strong>Pollution Type:</strong>
          </label>
          <select
            id="type-select"
            value={selectedType}
            onChange={(e) => setSelectedType(e.target.value)}
            style={{
              width: '100%',
              padding: '10px',
              marginTop: '5px',
              borderRadius: '4px',
              border: '1px solid #ddd',
              fontSize: '1rem'
            }}
          >
            {pollutionTypes.map(type => (
              <option key={type.value} value={type.value}>{type.label}</option>
            ))}
          </select>
        </div>

        <div style={{ flex: 1, minWidth: '200px' }}>
          <label htmlFor="priority-select">
            <strong>Priority Level:</strong>
          </label>
          <select
            id="priority-select"
            value={selectedPriority}
            onChange={(e) => setSelectedPriority(e.target.value)}
            style={{
              width: '100%',
              padding: '10px',
              marginTop: '5px',
              borderRadius: '4px',
              border: '1px solid #ddd',
              fontSize: '1rem'
            }}
          >
            {priorities.map(p => (
              <option key={p.value} value={p.value}>{p.label}</option>
            ))}
          </select>
        </div>
      </div>

      {loading ? (
        <div style={{ textAlign: 'center', padding: '40px', color: '#666' }}>
          Loading recommendations...
        </div>
      ) : recommendations.length > 0 ? (
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fill, minmax(350px, 1fr))',
          gap: '20px'
        }}>
          {recommendations.map(rec => (
            <div key={rec.id} style={{
              backgroundColor: '#fff',
              borderRadius: '8px',
              overflow: 'hidden',
              boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
              borderLeft: `5px solid ${getPriorityColor(rec.priority)}`
            }}>
              <div style={{
                padding: '15px',
                backgroundColor: getPriorityColor(rec.priority),
                color: '#fff',
                display: 'flex',
                alignItems: 'center',
                gap: '10px'
              }}>
                {getCategoryIcon(rec.category)}
                <div>
                  <h3 style={{ margin: 0 }}>{rec.title}</h3>
                  <small>{rec.category.replace(/_/g, ' ')}</small>
                </div>
              </div>

              <div style={{ padding: '15px' }}>
                <p style={{ margin: '0 0 10px 0', fontSize: '0.95rem' }}>
                  {rec.description}
                </p>

                {rec.action && (
                  <div style={{ marginBottom: '10px' }}>
                    <strong>Action:</strong>
                    <p style={{ margin: '5px 0', fontSize: '0.9rem' }}>
                      {rec.action}
                    </p>
                  </div>
                )}

                {rec.implementationSteps && (
                  <div style={{ marginBottom: '10px' }}>
                    <strong>Steps:</strong>
                    <ol style={{ margin: '5px 0', fontSize: '0.9rem', paddingLeft: '20px' }}>
                      {rec.implementationSteps.split('\n').map((step, idx) => (
                        <li key={idx}>{step}</li>
                      ))}
                    </ol>
                  </div>
                )}

                {rec.expectedImpact && (
                  <div style={{ marginBottom: '10px' }}>
                    <strong>Expected Impact:</strong>
                    <p style={{ margin: '5px 0', fontSize: '0.9rem', color: '#4caf50' }}>
                      ✓ {rec.expectedImpact}
                    </p>
                  </div>
                )}

                {rec.estimatedDaysToImpact && (
                  <div style={{
                    backgroundColor: '#f5f5f5',
                    padding: '10px',
                    borderRadius: '4px',
                    fontSize: '0.85rem',
                    color: '#666'
                  }}>
                    Estimated time to impact: <strong>{rec.estimatedDaysToImpact} days</strong>
                  </div>
                )}

                <div style={{
                  marginTop: '10px',
                  paddingTop: '10px',
                  borderTop: '1px solid #eee',
                  fontSize: '0.85rem',
                  color: '#999'
                }}>
                  Target: <strong>{rec.targetAudience}</strong>
                </div>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div style={{
          backgroundColor: '#fff',
          padding: '40px',
          borderRadius: '8px',
          textAlign: 'center',
          color: '#999'
        }}>
          <AlertCircle size={48} style={{ margin: '0 auto 20px', opacity: 0.5 }} />
          <p>No recommendations available for selected filters.</p>
        </div>
      )}

      <div style={{
        marginTop: '30px',
        backgroundColor: '#e3f2fd',
        padding: '20px',
        borderRadius: '8px',
        borderLeft: '4px solid #1976d2'
      }}>
        <h3 style={{ marginTop: 0 }}>How to Use These Recommendations</h3>
        <ul style={{ margin: 0 }}>
          <li>Individual actions can be implemented immediately by citizens</li>
          <li>Community actions require collective effort and coordination</li>
          <li>Policy changes need government implementation</li>
          <li>Infrastructure improvements require investment and planning</li>
          <li>Behavior changes require sustained effort and awareness</li>
          <li>Emergency actions should be taken urgently during crisis situations</li>
        </ul>
      </div>
    </div>
  );
};

export default Recommendations;
